// Pepr policy example
module.exports = async function PeprPolicy(pepr) {
  pepr.on('Pod').Created(async pod => {
    if (!pod.spec.securityContext) {
      pod.spec.securityContext = { runAsNonRoot: true };
    }
  });
};

